   251→  const bool include_peer_certificate_;
   252→  const bool include_tls_session_;
   253→  const bool charge_cluster_response_stats_;
   254→
   255→  // The stats for the filter.
   256→  ExtAuthzFilterStats stats_;
   257→
   258→  Filters::Common::ExtAuthz::MatcherSharedPtr allowed_headers_matcher_;
   259→  Filters::Common::ExtAuthz::MatcherSharedPtr disallowed_headers_matcher_;
   260→
   261→public:
   262→  // TODO(nezdolik): deprecate cluster scope stats counters in favor of filter scope stats
   263→  // (ExtAuthzFilterStats stats_).
   264→  const Stats::StatName ext_authz_ok_;
   265→  const Stats::StatName ext_authz_denied_;
   266→  const Stats::StatName ext_authz_error_;
   267→  const Stats::StatName ext_authz_invalid_;
   268→  const Stats::StatName ext_authz_failure_mode_allowed_;
   269→};
   270→
   271→using FilterConfigSharedPtr = std::shared_ptr<FilterConfig>;
   272→
   273→/**
   274→ * Per route settings for ExtAuth. Allows customizing the CheckRequest on a
   275→ * virtualhost\route\weighted cluster level.
   276→ */
   277→class FilterConfigPerRoute : public Router::RouteSpecificFilterConfig {
   278→public:
   279→  using ContextExtensionsMap = Protobuf::Map<std::string, std::string>;
   280→
   281→  FilterConfigPerRoute(
   282→      const envoy::extensions::filters::http::ext_authz::v3::ExtAuthzPerRoute& config)
   283→      : context_extensions_(config.has_check_settings()
   284→                                ? config.check_settings().context_extensions()
   285→                                : ContextExtensionsMap()),
   286→        check_settings_(config.has_check_settings()
   287→                            ? config.check_settings()
   288→                            : envoy::extensions::filters::http::ext_authz::v3::CheckSettings()),
   289→        disabled_(config.disabled()) {
   290→    if (config.has_check_settings() && config.check_settings().disable_request_body_buffering() &&
   291→        config.check_settings().has_with_request_body()) {
   292→      ExceptionUtil::throwEnvoyException(
   293→          "Invalid configuration for check_settings. Only one of disable_request_body_buffering or "
   294→          "with_request_body can be set.");
   295→    }
   296→  }
   297→
   298→  void merge(const FilterConfigPerRoute& other);
   299→
   300→  /**
   301→   * @return Context extensions to add to the CheckRequest.
   302→   */
   303→  const ContextExtensionsMap& contextExtensions() const { return context_extensions_; }
   304→  // Allow moving the context extensions out of this object.
   305→  ContextExtensionsMap&& takeContextExtensions() { return std::move(context_extensions_); }
   306→
   307→  bool disabled() const { return disabled_; }
   308→
   309→  envoy::extensions::filters::http::ext_authz::v3::CheckSettings checkSettings() const {
   310→    return check_settings_;
   311→  }
   312→
   313→private:
   314→  // We save the context extensions as a protobuf map instead of a std::map as this allows us to
   315→  // move it to the CheckRequest, thus avoiding a copy that would incur by converting it.
   316→  ContextExtensionsMap context_extensions_;
   317→  envoy::extensions::filters::http::ext_authz::v3::CheckSettings check_settings_;
   318→  bool disabled_;
   319→};
   320→
   321→/**
   322→ * HTTP ext_authz filter. Depending on the route configuration, this filter calls the global
   323→ * ext_authz service before allowing further filter iteration.
   324→ */
   325→class Filter : public Logger::Loggable<Logger::Id::ext_authz>,
   326→               public Http::StreamFilter,
   327→               public Filters::Common::ExtAuthz::RequestCallbacks {
   328→public:
   329→  Filter(const FilterConfigSharedPtr& config, Filters::Common::ExtAuthz::ClientPtr&& client)
   330→      : config_(config), client_(std::move(client)), stats_(config->stats()) {}
   331→
   332→  // Http::StreamFilterBase
   333→  void onDestroy() override;
   334→
   335→  // Http::StreamDecoderFilter
   336→  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers,
   337→                                          bool end_stream) override;
   338→  Http::FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;
   339→  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap& trailers) override;
   340→  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;
   341→
   342→  // Http::StreamEncoderFilter
   343→  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap& headers) override;
   344→  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers,
   345→                                          bool end_stream) override;
   346→  Http::FilterDataStatus encodeData(Buffer::Instance& data, bool end_stream) override;
   347→  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap& trailers) override;
   348→  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap& trailers) override;
   349→  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;
   350→
   351→  // ExtAuthz::RequestCallbacks
   352→  void onComplete(Filters::Common::ExtAuthz::ResponsePtr&&) override;
   353→
   354→private:
   355→  // Convenience function for the following:
   356→  // 1. If `validate_mutations` is set to true, validate header key and value.
   357→  // 2. If `decoder_header_mutation_rules` is set, check that mutation is allowed.
   358→  Filters::Common::MutationRules::CheckResult
   359→  validateAndCheckDecoderHeaderMutation(Filters::Common::MutationRules::CheckOperation operation,
   360→                                        absl::string_view key, absl::string_view value) const;
   361→
   362→  // Called when the filter is configured to reject invalid responses & the authz response contains
   363→  // invalid header or query parameters. Sends a local response with the configured rejection status
   364→  // code.
   365→  void rejectResponse();
   366→
   367→  absl::optional<MonotonicTime> start_time_;
   368→  void addResponseHeaders(Http::HeaderMap& header_map, const Http::HeaderVector& headers);
   369→  void initiateCall(const Http::RequestHeaderMap& headers);
   370→  void continueDecoding();
   371→  bool isBufferFull(uint64_t num_bytes_processing) const;
   372→  void updateLoggingInfo();
   373→
   374→  // This holds a set of flags defined in per-route configuration.
   375→  struct PerRouteFlags {
   376→    const bool skip_check_;
   377→    const envoy::extensions::filters::http::ext_authz::v3::CheckSettings check_settings_;
   378→  };
   379→  PerRouteFlags getPerRouteFlags(const Router::RouteConstSharedPtr& route) const;
   380→
   381→  // State of this filter's communication with the external authorization service.
   382→  // The filter has either not started calling the external service, in the middle of calling
   383→  // it or has completed.
   384→  enum class State { NotStarted, Calling, Complete };
   385→
   386→  // FilterReturn is used to capture what the return code should be to the filter chain.
   387→  // if this filter is either in the middle of calling the service or the result is denied then
   388→  // the filter chain should stop. Otherwise, the filter chain can continue to the next filter.
   389→  enum class FilterReturn { ContinueDecoding, StopDecoding };
   390→
   391→  Http::HeaderMapPtr getHeaderMap(const Filters::Common::ExtAuthz::ResponsePtr& response);
   392→  FilterConfigSharedPtr config_;
   393→  Filters::Common::ExtAuthz::ClientPtr client_;
   394→  Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
   395→  Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};
   396→  Http::RequestHeaderMap* request_headers_;
   397→  Http::HeaderVector response_headers_to_add_{};
   398→  Http::HeaderVector response_headers_to_set_{};
   399→  Http::HeaderVector response_headers_to_add_if_absent_{};
   400→  Http::HeaderVector response_headers_to_overwrite_if_exists_{};
   401→  State state_{State::NotStarted};
   402→  FilterReturn filter_return_{FilterReturn::ContinueDecoding};
   403→  Upstream::ClusterInfoConstSharedPtr cluster_;
   404→  // The stats for the filter.
   405→  ExtAuthzFilterStats stats_;
   406→  ExtAuthzLoggingInfo* logging_info_{nullptr};
   407→
   408→  // This is used to hold the final configs after we merge them with per-route configs.
   409→  bool allow_partial_message_{};
   410→  uint32_t max_request_bytes_{};
   411→
   412→  // Used to identify if the callback to onComplete() is synchronous (on the stack) or asynchronous.
   413→  bool initiating_call_{};
   414→  bool buffer_data_{};
   415→  bool skip_check_{false};
   416→  envoy::service::auth::v3::CheckRequest check_request_{};
   417→};
   418→
   419→} // namespace ExtAuthz
   420→} // namespace HttpFilters
   421→} // namespace Extensions
   422→} // namespace Envoy
   423→

